var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"흠~ 흐음~ 흠~","JPN":"ふん～ふふん～ふん～","ENG":"*Humming*","TWN":"哼～哼哼～哼～"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후후, 옳지~ 다들 가축처럼 넙죽 엎드려서 짖으렴!","JPN":"うふふ、よしよし～家畜のようにひれ伏して吠えなさい！","ENG":"Fu fuu, that's right...! Get down on your knees and bark like livestock!","TWN":"呵呵呵，沒錯～大家像畜生一樣在地上爬吧！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그리고 가서 내 원본을 찾는 거야.","JPN":"そして私のオリジナルを探し出すのよ。","ENG":"And go find my original.","TWN":"接下來，帶我去找本體吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"이 참을 수 없는 공복감을 채워 줄 수 있는 건, 내 원본 밖에 없으니까.","JPN":"この耐えがたい空腹感を満たすことができるのは、オリジナルしかいないから。","ENG":"The only thing that can satiate this unbearable hunger is the original.","TWN":"唯一能夠滿足這股難以忍受的饑餓的，只有我的本體了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"목숨만 붙어있으면 되니까, 팔 다리는 마음대로 해도 돼.","JPN":"手足は好きにしてもいいわ。息さえしていればいいの。","ENG":"As long as you bring her to me alive, do whatever you want with her limbs.","TWN":"只要能把她活著帶回來，要斷手斷腳都可以。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"제길, 그림자가 침식파로 하위 침식체를 장악하여 조종하고 있다!","JPN":"くそ、シャドウが侵食波で下位侵食体を操っている！","ENG":"Gah, the Shadow is controlling the lower C.O.s with Corruption rays!","TWN":"可惡，暗影正在透過侵蝕波，控制低階侵蝕體！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"방패를 들고, 모두 대열을 유지해!","JPN":"盾を持ち、隊列を維持せよ！","ENG":"Raise your shields and maintain formation!","TWN":"舉起盾牌，所有人保持陣列！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"침식체가 대열 사이에 파고들지 못하도록 막아!","JPN":"侵食体が隊列に割り込めないように防げ！","ENG":"Stop the C.O.s from squirming pass our ranks!","TWN":"抵擋低階侵蝕體的衝擊！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"지금이다! 전대원, 사격 개시!","JPN":"今だ！　全隊員、射撃開始！","ENG":"NOW! All units, fire!","TWN":"就是現在！戰隊員，開火！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"잔챙이들을 제압해! 그림자의 요격은 야크샤 전대에게 맡긴다!","JPN":"雑魚を制圧しろ！　シャドウの迎撃はヤクシャー戦隊に任せる！","ENG":"Kill the small pests! The Yaksha Division will be in charge of taking down the Shadow!","TWN":"壓制住那些傢伙！暗影就交給夜叉戰隊阻擊了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"어머, 역시 이 시대의 관리국은 만만하지 않네.","JPN":"あら、やっぱりこの時代の管理局はおいそれといかないわね。","ENG":"Oh, my. The Administration of this era isn't easy.","TWN":"喔，喔……，這個時代的管理局真不簡單啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"다들 군기가 딱 잡혔어.","JPN":"軍紀がしっかりしてるわ。","ENG":"They're so organized and disciplined.","TWN":"軍紀嚴明。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"우후훗, 하지만……!","JPN":"うふふ、でも……！","ENG":"Fu fuu, but...!","TWN":"呵呵呵，不過嘛……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장! 쏘지 마! 아군이다!","JPN":"くそ！　撃つな！　味方だ！","ENG":"Dammit! Cease fire! It's an ally!","TWN":"該死！別開槍！是友軍！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"똑바로 서 있을 수가 없어! 균형을 못 잡겠어!","JPN":"まともに立っていられない！　バランスが崩れる！","ENG":"I can't stand upright! I can't keep my balance!","TWN":"我站不起來了啊！沒辦法保持平衡！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"진정해! 적에게 현혹되지 말라고!!","JPN":"落ち着け！　敵に惑わされるな！","ENG":"Calm down! Don't be fooled by the enemy!","TWN":"冷靜下來！不要被敵人欺騙了！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"아하하하하하하핫……!!","JPN":"あはははははは……！！","ENG":"AH HAHAHAHAHA...!!","TWN":"啊哈哈哈哈哈……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"기분 최고네! 이렇게……! 이런 식으로 다시 기회를 얻게 될 줄이야……!","JPN":"最高の気分だわ……！　こうして……またチャンスが巡ってくるなんて……！","ENG":"This feels wonderful! I never thought that I'd get another chance like this...!","TWN":"感覺棒極了！像這樣……！沒想到我還能有這樣的機會……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그러니 어서……! 어서 원본을 잡아먹고 더 완전해져야만 해!","JPN":"だから早く……！　オリジナルを喰べて、完全体にならないと！","ENG":"And now...! I just need to consume the original and become more complete!","TWN":"所以快點吧……！讓我吞掉你，變得更加完整！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_NULL_DOP","text":{"KOREA":"그렇게 되면……!!","JPN":"そうすれば……！！","ENG":"Then...!!","TWN":"這樣一來……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"젠장, 저기 보인다……! 저게 그림자라는 녀석이야……!?","JPN":"くそ……見えるぞ……！　あれがシャドウってやつなのか……！？","ENG":"Gah, I see the Shadow...! That's...?!","TWN":"該死，看那裡……！那傢伙就是暗影……？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"잠깐, 저 녀석의 얼굴……!!","JPN":"待て、あいつの顔……！！","ENG":"Wait... her face...!!","TWN":"等等，那傢伙的臉……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"나랑 똑같이 생겼잖아! 꼬리랑 귀도 있어!","JPN":"アタシとそっくりじゃないか！　耳と尻尾もある！","ENG":"She looks exactly like me! Even with the ears and tail!","TWN":"她長得和我一模一樣！連尾巴和耳朵也是！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};